def validate(args, output):
    nums = args[0]
    if not isinstance(output, list) or len(output) != len(nums):
        return False
    from collections import Counter
    # every even index must hold an even number, every odd index an odd number
    for i, v in enumerate(output):
        if not isinstance(v, int):
            return False
        if i % 2 == 0 and v % 2 != 0:
            return False
        if i % 2 == 1 and v % 2 != 1:
            return False
    # output must be a permutation of the input
    return Counter(output) == Counter(nums)

