function validate(args, output) {
    const nums = args[0];
    if (!Array.isArray(output) || output.length !== nums.length) return false;
    for (let i = 0; i < output.length; i++) {
        if (typeof output[i] !== 'number') return false;
        if (i % 2 === 0 && output[i] % 2 !== 0) return false;
        if (i % 2 === 1 && Math.abs(output[i]) % 2 !== 1) return false;
    }
    const sortedOut = output.slice().sort((a, b) => a - b);
    const sortedIn = nums.slice().sort((a, b) => a - b);
    for (let i = 0; i < sortedOut.length; i++) {
        if (sortedOut[i] !== sortedIn[i]) return false;
    }
    return true;
}

