class Solution:
    def sortArrayByParityII(self, nums):
        evens = [x for x in nums if x % 2 == 0]
        odds = [x for x in nums if x % 2 == 1]
        result = []
        ei, oi = 0, 0
        for i in range(len(nums)):
            if i % 2 == 0:
                result.append(evens[ei]); ei += 1
            else:
                result.append(odds[oi]); oi += 1
        return result

