var sortArrayByParityII = function(nums) {
    const evens = nums.filter(x => x % 2 === 0);
    const odds = nums.filter(x => x % 2 === 1);
    const result = [];
    let ei = 0, oi = 0;
    for (let i = 0; i < nums.length; i++) {
        if (i % 2 === 0) result.push(evens[ei++]);
        else result.push(odds[oi++]);
    }
    return result;
};
